using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
struct node
{
	int x;
	int y;
}b[MAXN];
bool cmp(node a,node b)
{
	if(a.x==b.x)return a.y>b.y;
	else return a.x>b.x;
}
int n,a[MAXN],d[MAXN],len=1;
signed main(void)
{
	n=read();
	FOR(i,1,n)
	{
		b[i].x=read();
		b[i].y=read();
	}
	sort(b+1,b+n+1,cmp);
	FOR(i,1,n)
	{	
		a[i]=b[i].y;
	}
	d[1]=a[1];
	FOR(i,2,n)
	{
		int pos=lower_bound(d+1,d+len+1,a[i])-d;
		d[pos]=a[i];
		if(pos==len+1)++len;
	}
	write(len);
	return false;
}
